insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:3-7-supply-side-policies:mcq:aa4ecdee', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Privatisation is expected to increase efficiency mainly because...", "options": ["It increases the size of the public sector", "Government ownership always charges the lowest prices", "The profit motive pushes newly private firms to cut costs and innovate", "It removes all competition from the market"]}'::jsonb, '{"answer": 2, "explain": "Once in the private sector, firms are driven by profit maximisation to cut average costs and innovate to win customers — unlike a state monopoly with no profit incentive."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:0869366a', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Which of the following is the best description of price stability?", "options": ["The general price level never changes", "Inflation remains constant, whatever the rate", "The general price level grows at a low, acceptable rate", "Interest rates stay the same"]}'::jsonb, '{"answer": 2, "explain": "Price stability means low, predictable growth in prices (e.g. the 2% target) — ''inflation remains constant'' fails because it could be constant at a very high rate."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:878713f7', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Which is a genuine COST of supply-side policy, rather than a benefit?", "options": ["Lower inflationary pressure", "An improvement in the balance of payments", "A fall in structural unemployment", "The large opportunity cost of financing expensive infrastructure projects"]}'::jsonb, '{"answer": 3, "explain": "The other three are benefits. Expensive projects like HS2 carry a large opportunity cost — the money could have funded other services."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:5adf8630', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "An increase in the productive capacity of the economy is best shown as...", "options": ["A leftward shift in aggregate supply", "A rightward shift in the economy''s aggregate supply / potential output", "A rise in interest rates", "A movement along the demand curve"]}'::jsonb, '{"answer": 1, "explain": "Supply-side policies push the economy''s potential output curve outward (to the right), allowing more to be produced at every price level."}'::jsonb),
('economics:3-7-supply-side-policies:mcq:31f2d44f', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'mcq', 'mcq', 1, '{"question": "Why can cutting direct taxes on workers increase inflation, even though it is meant to help price stability?", "options": ["It directly increases the price of exports", "It raises disposable income, which can increase demand and cause demand-pull inflation", "It always raises the exchange rate", "It reduces the productive capacity of the economy"]}'::jsonb, '{"answer": 1, "explain": "Higher take-home pay increases spending power. If demand rises faster than the economy''s capacity to supply, inflation rises — the exam''s classic supply-side contradiction."}'::jsonb),
('economics:3-7-supply-side-policies:tf:49ccdecb', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Supply-side policies mainly work by managing the level of demand."}'::jsonb, '{"answer": false, "explain": "They work by increasing the economy''s productive CAPACITY — demand management is the job of fiscal and monetary policy."}'::jsonb),
('economics:3-7-supply-side-policies:tf:21a76beb', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Cutting income tax can act like a pay rise for workers without raising costs to firms."}'::jsonb, '{"answer": true, "explain": "Because it isn''t the firm paying more, only the worker keeping more of the same wage — so it increases the incentive to work without adding to production costs."}'::jsonb),
('economics:3-7-supply-side-policies:tf:0db39dad', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Privatisation always reduces the quality of a service."}'::jsonb, '{"answer": false, "explain": "The theory is the opposite: the profit motive is expected to drive newly private firms to cut costs, innovate and better meet consumer needs."}'::jsonb),
('economics:3-7-supply-side-policies:tf:21d349b4', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "A rightward shift in supply gives both a lower price and a higher quantity."}'::jsonb, '{"answer": true, "explain": "More is supplied at every price, so the new equilibrium settles at a lower price and higher quantity — assuming firms pass on the lower costs."}'::jsonb),
('economics:3-7-supply-side-policies:tf:f1ee6f2f', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Supply-side policies always take effect quickly."}'::jsonb, '{"answer": false, "explain": "Most take years — education reforms take a generation to reach the workforce, and infrastructure like HS2 takes over a decade to build."}'::jsonb),
('economics:3-7-supply-side-policies:tf:e4d566a9', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Reducing unemployment benefits can never be justified because it always increases inequality."}'::jsonb, '{"answer": false, "explain": "It is genuinely mixed: it may increase inequality for those affected, but it can also increase the incentive to work, which examiners expect you to weigh, not just reject."}'::jsonb),
('economics:3-7-supply-side-policies:tf:8aedc9df', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Cutting direct taxes to boost work incentives can also cause demand-pull inflation."}'::jsonb, '{"answer": true, "explain": "Higher disposable income can raise demand faster than supply can respond — the exam''s classic supply-side contradiction."}'::jsonb),
('economics:3-7-supply-side-policies:tf:48984859', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tf', 'tf', 1, '{"question": "Government spending on supply-side policy has no opportunity cost, because it grows the economy."}'::jsonb, '{"answer": false, "explain": "Every pound spent still has an opportunity cost — it could have funded other services, lower taxes, or less borrowing, whether or not it eventually grows the economy."}'::jsonb),
('economics:3-7-supply-side-policies:learn:e2a69011', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'learn', 'mcq', 1, '{"readingTitle": "What is a supply-side policy?", "reading": "<p><strong>Supply-side policies are government policies that aim to increase an economy''s productive capacity</strong> — its ability to produce goods and services — rather than managing the level of demand directly. Contrast this with <strong>fiscal policy</strong> (government spending and taxation) and <strong>monetary policy</strong> (interest rates), which mainly work by shifting <strong>demand</strong>.</p>\n<h4>Why this matters</h4>\n<ul>\n<li>If <strong>aggregate demand</strong> grows but the economy''s <strong>capacity to supply</strong> doesn''t keep pace, the result is <strong>demand-pull inflation</strong> rather than genuine growth.</li>\n<li>Supply-side policies shift the economy''s potential output <strong>outwards</strong>, allowing higher sustainable growth without the extra inflation.</li>\n</ul>\n<h4>The main types — learn to classify a described policy</h4>\n<ul>\n<li><strong>Education and training</strong> — improves the skills and qualifications of the workforce (raises \"human capital\").</li>\n<li><strong>Infrastructure investment</strong> — transport, energy, broadband; lowers costs and journey times for firms.</li>\n<li><strong>Reducing direct taxes</strong> — lower <strong>income tax</strong> increases the incentive to work; lower <strong>corporation tax</strong> lets firms keep more profit to invest.</li>\n<li><strong>Reducing benefits</strong> — aims to increase the incentive to take a job rather than claim benefits.</li>\n<li><strong>Trade union reform</strong> — restricting union power makes it easier for firms to keep wage costs down.</li>\n<li><strong>Privatisation</strong> — selling state-owned firms into the private sector, where the profit motive is expected to drive efficiency.</li>\n<li><strong>Deregulation</strong> — removing rules that create barriers to entry, opening markets to more competition.</li>\n<li><strong>Promoting competition</strong> — e.g. the <strong>Competition and Markets Authority (CMA)</strong> can block mergers that would reduce competition.</li>\n</ul>\n<h4>Watch the classic MCQ trap</h4>\n<ul>\n<li>A real exam MCQ asked why a £50bn railway line is a supply-side policy. The correct answer was that it <strong>improves journey times for people travelling to work</strong> — the direct productive-capacity effect. Distractors about construction firms'' profits, the tax cut it could have funded, or import demand for materials are all <strong>side-effects</strong>, not the supply-side mechanism itself.</li>\n</ul>", "question": "Which of these is a supply-side policy?", "options": ["Increasing government spending on unemployment benefits", "Reducing unemployment benefits to encourage people into work", "Raising taxes to reduce consumer spending", "Cutting interest rates to encourage borrowing"]}'::jsonb, '{"answer": 1, "explain": "Reducing benefits targets the economy''s productive capacity (labour supply) directly. Cutting interest rates is monetary policy; raising taxes to cut spending is fiscal/demand policy."}'::jsonb),
('economics:3-7-supply-side-policies:learn:a4f41535', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'learn', 'mcq', 1, '{"readingTitle": "How supply-side policies achieve economic objectives", "reading": "<p>The exam expects you to explain the <strong>chain of reasoning</strong> from a named supply-side policy through to a macroeconomic objective. Learn these three chains.</p>\n<h4>Economic growth and employment</h4>\n<ul>\n<li>A better-educated, more skilled workforce → less <strong>occupational/structural unemployment</strong>, because workers'' skills better match the jobs available.</li>\n<li>Improved infrastructure (transport, internet) → lower costs for firms → easier to expand production.</li>\n<li>Lower direct taxes → higher after-tax profits → more investment → today''s small firms become tomorrow''s large employers.</li>\n<li>All of this raises the economy''s <strong>productive capacity</strong>, so growth and employment can rise together.</li>\n</ul>\n<h4>Price stability</h4>\n<ul>\n<li>Increased productive capacity → an increase in <strong>supply</strong> → lower costs of production economy-wide → less inflationary pressure, helping keep inflation near the government''s <strong>2% target</strong>.</li>\n<li><strong>The exam''s favourite contradiction:</strong> cutting direct taxes on workers is meant to raise incentives to work, but it also raises <strong>disposable income</strong> — which can increase demand and cause <strong>demand-pull inflation</strong>. A policy aimed at price stability can end up working against it.</li>\n</ul>\n<h4>The balance of payments</h4>\n<ul>\n<li>Lower costs of production → UK firms can sell at more <strong>competitive prices</strong> internationally, and improved quality also raises demand for UK goods abroad.</li>\n<li>Both effects raise <strong>exports</strong>, which improves the balance of payments (specifically the balance of trade).</li>\n</ul>", "question": "How can education and training help achieve price stability?", "options": ["It directly lowers interest rates", "It raises the exchange rate", "It increases government spending on benefits", "A more productive workforce lets supply keep up with demand, easing inflationary pressure"]}'::jsonb, '{"answer": 3, "explain": "A more productive workforce raises supply so it can keep pace with demand, reducing demand-pull and cost-push inflation — one mark for productivity, one for linking it to inflation/price stability."}'::jsonb),
('economics:3-7-supply-side-policies:learn:7dc07f5e', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'learn', 'mcq', 1, '{"readingTitle": "The benefits of supply-side policies", "reading": "<p>Real exam extracts reward evaluating benefits with <strong>real evidence</strong>, not just generic statements.</p>\n<h4>Targeting specific markets</h4>\n<ul>\n<li>Spending can be aimed precisely — e.g. over <strong>£180 million</strong> was made available to attract trainee teachers in shortage subjects like maths and sciences.</li>\n<li><strong>HS2</strong> is designed to boost growth specifically in the north of England by improving links to the capital.</li>\n</ul>\n<h4>Reducing inflation</h4>\n<ul>\n<li>A rightward shift in supply gives a <strong>lower equilibrium price AND a higher equilibrium quantity</strong> — but only if producers actually pass their lower costs on as lower prices.</li>\n</ul>\n<h4>Employment, growth, and the balance of payments</h4>\n<ul>\n<li>Firms need more workers to raise output to meet expanded demand — though if the extra output comes from <strong>automation</strong> instead, the employment benefit is limited.</li>\n<li>Lower costs and higher quality both raise exports, improving the balance of trade.</li>\n</ul>\n<h4>Income distribution — the exam''s data-driven angle</h4>\n<ul>\n<li>A real exam extract compared Argentina and Finland: Finland spends more on education per student (25.8% of GDP per capita vs Argentina''s 21.8%) — and Finland''s income distribution is far more equal (richest 10% hold 22.4% vs Argentina''s 30.3%; poorest 10% hold 3.9% vs Argentina''s 1.8%).</li>\n<li>Mechanism: government-funded education benefits ALL students, not just the privately educated, so it raises equality of opportunity and lets skilled workers earn higher wages — narrowing the income gap.</li>\n</ul>\n<h4>Correcting market failure</h4>\n<ul>\n<li>Subsidising a good with <strong>positive externalities</strong> (e.g. vaccinations) encourages producers to supply more and consumers to take up something that benefits third parties too. UK measles vaccination coverage rose from 81% (2004) to over 91% (2023), with almost no deaths since 2013.</li>\n</ul>", "question": "Extract data shows Finland spends more on education than Argentina, and also has a more equal income distribution. What does this suggest?", "options": ["Argentina''s richest 10% pay more tax than Finland''s", "Investment in education is likely to be an important factor behind more equal income distribution", "Education spending has no effect on income distribution", "Vaccination rates explain the difference"]}'::jsonb, '{"answer": 1, "explain": "The data links higher education spending to a smaller gap between the richest and poorest 10% — because education widens opportunity for all, not just the privately educated."}'::jsonb),
('economics:3-7-supply-side-policies:learn:487d68dc', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'learn', 'mcq', 1, '{"readingTitle": "The costs of supply-side policies", "reading": "<p>Evaluate questions on this topic are almost always about <strong>weighing named costs against named benefits</strong> — learn the costs with real examples.</p>\n<h4>Financial cost and opportunity cost</h4>\n<ul>\n<li>Supply-side projects are expensive: <strong>HS2</strong> is budgeted at roughly £45–55.7bn (up from an initial £32.7bn), and the <strong>Elizabeth Line</strong> cost £18.9bn against an original £14.8bn budget.</li>\n<li>Every pound spent has an <strong>opportunity cost</strong> — it could have funded other services, lower taxes, or reduced government borrowing instead.</li>\n</ul>\n<h4>Time lags</h4>\n<ul>\n<li>Projects like HS2 take well over a decade from announcement to completion. Education and training reforms take years to filter through, because trainees must complete their courses before joining the workforce.</li>\n</ul>\n<h4>Opposition and unintended consequences</h4>\n<ul>\n<li>Reducing benefits faces opposition from charities and groups representing the least well-off, and can genuinely worsen income inequality for the poorest.</li>\n<li>Reducing trade union power can provoke opposition from unions — cracking down too hard can even increase industrial action rather than reduce it.</li>\n<li>Competition policy can be blocked outright: the CMA stopped the proposed <strong>Sainsbury''s–Asda merger</strong>.</li>\n<li>Cutting income tax can backfire: some workers may choose to work <strong>fewer</strong> hours for the same take-home pay, rather than more — the opposite of the intended effect on labour supply.</li>\n</ul>\n<h4>Crowding out</h4>\n<ul>\n<li>Large public sector spending can <strong>crowd out</strong> the private sector — though private firms also gain from winning government contracts, so the effect isn''t one-sided.</li>\n</ul>\n<h4>The exam''s built-in contradiction — learn this one</h4>\n<ul>\n<li>Cutting direct taxes on workers and firms is meant to increase incentives to work and invest — but it also raises disposable income, which <strong>could also lead to rising inflation</strong>, directly undermining the price-stability objective the policy was meant to serve.</li>\n</ul>", "question": "Why might cutting income tax fail to increase the number of hours people work?", "options": ["Some workers may choose to work fewer hours for the same take-home pay", "Lower income tax reduces the incentive to work at all", "Income tax cuts always increase unemployment", "It automatically raises benefits instead"]}'::jsonb, '{"answer": 0, "explain": "If take-home pay rises for the same hours, some workers value extra leisure time and choose to work LESS, not more — the opposite of the policy''s intended incentive effect."}'::jsonb),
('economics:3-7-supply-side-policies:misc:4f0b19c3', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Vaccinations are subsidised because they are useful to people.\"</p><p><strong>✅ The correct idea:</strong> The examiners were explicit here: ''Most candidates could demonstrate why vaccinations are useful, but did not explicitly state or explain how subsidies work.'' Simply saying vaccines are good for health only shows knowledge of the OUTCOME — it doesn''t answer ''explain why governments give SUBSIDIES''. The mark scheme wanted the MECHANISM: a subsidy lowers the cost to producers, making it cheaper/more widely available, or it encourages producers to increase output of an expensive vaccine, or it corrects the positive externality by encouraging uptake that would otherwise be too expensive. Always explain the POLICY TOOL asked about, not just the general benefit of the thing it targets.</p>", "question": "A question asks ''explain why governments subsidise vaccinations.'' Which answer would the examiners mark as INCOMPLETE?", "options": ["A subsidy lowers the cost to producers, making the vaccine cheaper and more widely available", "A subsidy encourages producers to increase output of an expensive vaccine", "Vaccines are good because they stop people getting ill", "A subsidy corrects the positive externality by encouraging take-up"]}'::jsonb, '{"answer": 2, "explain": "''Vaccines are good'' describes the benefit of the vaccine itself, not how a SUBSIDY works — the examiners flagged exactly this gap."}'::jsonb),
('economics:3-7-supply-side-policies:misc:5e89f3e9', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"I''ll analyse a benefit, then evaluate by naming a completely different cost.\"</p><p><strong>✅ The correct idea:</strong> This paper''s own Misconception box: ''Evaluation is awarded for making a judgement or writing an evaluative point that matches with the preceding point... A common error was that candidates would analyse a benefit... and then attempt evaluation by writing that there is an opportunity cost of government spending WITHOUT LINKING this argument to how it would lower the potential gains.'' Evaluation only scores if it directly qualifies the point you just made — e.g. ''vaccinations reduce illness AND free up NHS resources, HOWEVER the financial cost of the subsidy may outweigh those savings.'' A random extra cost bolted on at the end, unconnected to your analysis, does not count as evaluation.</p>", "question": "According to the examiners, when does an ''evaluation'' point actually earn marks?", "options": ["When it repeats the analysis point in different words", "Only when it uses the word ''however''", "When it directly links to and qualifies the analysis point made just before it", "When it introduces any new cost, regardless of the previous point"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme''s own Misconception box says evaluation must MATCH the preceding point — an unconnected extra point doesn''t count, however negative it sounds."}'::jsonb),
('economics:3-7-supply-side-policies:misc:23257942', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"For the £50bn railway MCQ, the answer must be about the construction firms'' profits or the tax cut it could have funded.\"</p><p><strong>✅ The correct idea:</strong> Both are real effects, but they are DEMAND-side or opportunity-cost effects, not the reason it counts as a SUPPLY-SIDE policy. The correct answer was ''journey times will be improved for people travelling to work'' — because that is what directly raises the economy''s productive capacity (workers reach jobs faster, firms move goods faster). Builders'' profits are a demand-side effect of the spending; the tax cut foregone is an opportunity cost, not a supply-side mechanism; and demand for imported materials is also a demand-side knock-on. When an MCQ asks WHY something is a supply-side policy, find the option that improves capacity to produce — not the side-effects of the spending.</p>", "question": "The government spends £50bn on a new railway line. Why is this a supply-side policy?", "options": ["The money could have funded a tax cut instead", "It improves journey times for people travelling to work", "It raises demand for imported building materials", "Construction companies achieve greater profits"]}'::jsonb, '{"answer": 1, "explain": "Only the journey-time effect directly raises productive capacity. The other three are demand-side or opportunity-cost effects, not the supply-side mechanism the question is asking about."}'::jsonb),
('economics:3-7-supply-side-policies:misc:d1386118', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"For ''evaluate the COSTS of supply side policy'', I can write mostly about its benefits instead.\"</p><p><strong>✅ The correct idea:</strong> The examiners flagged this directly: ''Some candidates used the majority, or all, of their answer to analyse and evaluate the impacts of supply side policy rather than their COSTS'' — and separately noted candidates ''found the focus on the costs... more difficult to explain using chains of reasoning'' than benefits. If the question asks for costs, every analysis point must BE a cost (financial cost, opportunity cost, cutting work incentives, raising inflation, worsening inequality, industrial disputes) — benefits only belong in your evaluation, as a comment that OFFSETS a cost you''ve already named, e.g. ''however, this cost may be outweighed by increased consumer confidence from price stability.''</p>", "question": "A question asks you to ''evaluate the COSTS of supply-side policy.'' What did examiners say some candidates wrongly did?", "options": ["Named too many different costs", "Spent most of their answer analysing the general benefits instead of the costs", "Wrote a judgement at the end", "Used too many real-world examples"]}'::jsonb, '{"answer": 1, "explain": "Examiners explicitly noted candidates who focused on benefits rather than costs — always answer the COMMAND WORD''s actual focus, using benefits only to offset a cost in evaluation."}'::jsonb),
('economics:3-7-supply-side-policies:misc:86c99a67', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Extract 3(i) just wants me to spot that Finland spends more on education than Argentina.\"</p><p><strong>✅ The correct idea:</strong> That''s only worth 1 of the 2 marks. The mark scheme is explicit: ''1 mark for correctly identifying that Finland spends a greater percentage on education. 2nd mark for CLEARLY LINKING this to the income shares.'' The same pattern appears in Extract 3''s part (ii): ''2 marks for a clear explanation, 1 mark for an answer without an explanatory link e.g. more spending per student / higher salaries for teachers.'' Data questions on this topic almost always reward a fact PLUS its consequence — quoting a number from the table is only ever the first half of the answer.</p>", "question": "A data question gives 2 marks for using a table. What does the mark scheme usually require for BOTH marks?", "options": ["Two different data points, unlinked", "A rounded estimate of the data", "The correct data point PLUS an explicit link to what it explains", "A comparison with a country not in the table"]}'::jsonb, '{"answer": 2, "explain": "Both mark schemes here (income shares AND GDP per capita) award the 2nd mark only for linking the data to the actual question — a bare fact from the table earns just 1 mark."}'::jsonb),
('economics:3-7-supply-side-policies:tips:31c7bc2e', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tips', 'mcq', 1, '{"readingTitle": "classification — Classifying MCQs: find the supply-side MECHANISM", "reading": "<p>Roughly half the MCQs on this paper are pure classification — and the distractors follow predictable patterns.</p>\n<ul>\n<li><strong>Monetary policy distractors:</strong> \"changing/raising interest rates\", \"encouraging bank lending\" — these are Bank of England tools, not government supply-side policy.</li>\n<li><strong>Trade policy distractors:</strong> \"imposing taxes/tariffs on imports\" — a trade measure, not a productive-capacity measure.</li>\n<li><strong>Outcome, not policy:</strong> \"lowering the rate of price rises\" or \"increase economic growth\" describe a GOAL, not the policy tool that achieves it.</li>\n<li><strong>Wrong direction:</strong> \"increase unemployment benefits\" is the OPPOSITE of the usual supply-side move (which is to REDUCE benefits to raise work incentives).</li>\n</ul>\n<p>Test every option against: \"does this directly raise the economy''s ability to PRODUCE?\"</p>", "question": "Which of these would NOT count as a supply-side policy?", "options": ["Reducing corporation tax", "Raising interest rates to control spending", "Reducing trade union power", "Investing in infrastructure"]}'::jsonb, '{"answer": 1, "explain": "Raising interest rates is a monetary policy tool used to manage demand, not a supply-side measure aimed at productive capacity."}'::jsonb),
('economics:3-7-supply-side-policies:tips:03b43151', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tips', 'mcq', 1, '{"readingTitle": "definition — ''State'' and ''explain'': know the difference in elements", "reading": "<p>Both question types typically carry 2 marks, but they reward different things.</p>\n<ul>\n<li><strong>''State what is meant by price stability''</strong> needs a TWO-ELEMENT definition: the general price level grows at a LOW rate (1), such as the government''s 2% target (1). \"Prices do not go up\" alone is only worth 1.</li>\n<li><strong>''Explain how X policy achieves Y''</strong> needs a MECHANISM plus a LINK: e.g. education and training create a more productive workforce (1), so supply can keep up with demand / cost-push inflation is less likely (2). Just \"it improves skills\" without the link to the objective is only 1 mark.</li>\n<li>The same pattern applies to ''explain why governments subsidise vaccinations'' — state the mechanism (lower cost to producers, or correcting a positive externality), not just that vaccines are useful.</li>\n</ul>", "question": "For ''explain how education and training may help achieve price stability'', what earns the SECOND mark?", "options": ["Linking the more productive workforce to reduced cost-push or demand-pull inflation", "Repeating that education improves skills", "Stating the government''s inflation target", "Naming a different supply-side policy"]}'::jsonb, '{"answer": 0, "explain": "The first mark is for the mechanism (more productive workforce); the second mark needs that mechanism explicitly LINKED to price stability/inflation."}'::jsonb),
('economics:3-7-supply-side-policies:tips:f58496c9', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tips', 'mcq', 1, '{"readingTitle": "data — Extract tables: quote the figure, then link it", "reading": "<p>Both table-based questions on this paper follow the identical mark scheme structure.</p>\n<ul>\n<li><strong>1st mark:</strong> correctly quote or identify the relevant figures from the table (e.g. \"Finland spends 25.8% of GDP per capita on education, more than Argentina''s 21.8%\").</li>\n<li><strong>2nd mark:</strong> explicitly LINK that figure to what the question actually asks (e.g. \"...and Finland''s richest 10% hold a smaller income share, 22.4% vs 30.3%\").</li>\n<li>Stopping after the first mark is the single most common way to drop marks on data questions — a fact from the table with no explanatory link is capped at 1 mark, however accurate it is.</li>\n</ul>", "question": "A table shows Finland spends more on education than Argentina and has a smaller rich–poor income gap. What earns the SECOND mark?", "options": ["Explicitly linking the higher education spending to the smaller income gap", "Rounding the percentages to whole numbers", "Restating the education spending figures a second time", "Naming a third country not shown in the table"]}'::jsonb, '{"answer": 0, "explain": "The first mark is for correctly reading the data; the second mark requires linking that data explicitly to the actual question asked."}'::jsonb),
('economics:3-7-supply-side-policies:tips:894b1c21', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: pair every point, and answer the actual command word", "reading": "<p>Every 6-mark question on this paper follows AO2 (1 mark) + AO3a analysis (2 marks) + AO3b evaluation (3 marks), marked by best-fit level.</p>\n<ul>\n<li><strong>Level 3 (5–6):</strong> good application; developed chains of reasoning; a fully supported judgement weighing both sides.</li>\n<li><strong>Level 2 (3–4):</strong> good application; analysis largely in single, undeveloped effects; a judgement that isn''t fully supported.</li>\n<li><strong>Level 1 (1–2):</strong> no application; limited analysis; unsupported evaluation.</li>\n<li><strong>Pair every point:</strong> the mark scheme''s own Misconception box warns that evaluation only counts if it directly MATCHES the analysis point just made — a random extra point doesn''t score.</li>\n<li><strong>Answer the actual focus:</strong> if the question asks for COSTS, every analysis point must be a cost — examiners noted candidates who wrote mostly about benefits instead lost marks. Use benefits only to OFFSET a cost in your evaluation.</li>\n<li>Signal your final judgement clearly, e.g. with \"Overall\" or \"In conclusion\".</li>\n</ul>", "question": "In the Level of response mark scheme, what separates Level 3 from Level 2 evaluation?", "options": ["Level 2 always scores zero for evaluation", "Level 3 has a fully supported judgement weighing both sides; Level 2''s judgement is not fully supported", "Level 3 uses more difficult vocabulary", "Level 3 does not require a judgement at all"]}'::jsonb, '{"answer": 1, "explain": "Both levels can include a judgement, but only Level 3 develops it from properly weighing up the arguments on both sides."}'::jsonb),
('economics:3-7-supply-side-policies:fib:93238a59', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'fib', 'fib', 2, '{"question": "Supply-side policies aim to increase an economy''s ___B1___ capacity, rather than managing ___B2___.", "blankOptions": {"B1": ["monetary", "private", "productive", "corporation"], "B2": ["corporation", "demand", "inflationary", "supply"]}}'::jsonb, '{"blanks": {"B1": "productive", "B2": "demand"}}'::jsonb),
