('economics:3-7-supply-side-policies:fib:d0ee7c35', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'fib', 'fib', 2, '{"question": "A cut in direct taxes can increase incentives to work, but by raising disposable income it could also lead to rising ___B1___ — a direct ___B2___ with the aim of price stability.", "blankOptions": {"B1": ["private", "supply", "Privatisation", "inflation"], "B2": ["private", "opportunity", "contradiction", "inflationary"]}}'::jsonb, '{"blanks": {"B1": "inflation", "B2": "contradiction"}}'::jsonb),
