('economics:3-7-supply-side-policies:match:0ecc18c5', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Supply-side policy”?", "options": ["Government policy aimed at increasing the economy''s productive capacity, rather than managing demand", "A tax on a firm''s profits", "Transport, energy and communication networks that support economic activity", "A tax on income or profit, such as income tax or corporation tax"]}'::jsonb, '{"answer": 0, "explain": "“Supply-side policy” means: Government policy aimed at increasing the economy''s productive capacity, rather than managing demand"}'::jsonb),
('economics:3-7-supply-side-policies:match:d6bfbd2d', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Human capital”?", "options": ["The skills, knowledge and qualifications that make a worker productive", "Policy that restricts unions'' power to negotiate pay and conditions", "Government policy aimed at increasing the economy''s productive capacity, rather than managing demand", "Selling a state-owned organisation into the private sector"]}'::jsonb, '{"answer": 0, "explain": "“Human capital” means: The skills, knowledge and qualifications that make a worker productive"}'::jsonb),
('economics:3-7-supply-side-policies:match:ce1022ab', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Infrastructure”?", "options": ["Transport, energy and communication networks that support economic activity", "The skills, knowledge and qualifications that make a worker productive", "Removing rules and regulations that create barriers to entry in a market", "The next best alternative given up when a choice is made"]}'::jsonb, '{"answer": 0, "explain": "“Infrastructure” means: Transport, energy and communication networks that support economic activity"}'::jsonb),
('economics:3-7-supply-side-policies:match:c844fe15', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Direct tax”?", "options": ["A benefit to a third party not involved in a transaction, e.g. from vaccination", "The skills, knowledge and qualifications that make a worker productive", "The UK body that can block mergers that would reduce competition", "A tax on income or profit, such as income tax or corporation tax"]}'::jsonb, '{"answer": 3, "explain": "“Direct tax” means: A tax on income or profit, such as income tax or corporation tax"}'::jsonb),
('economics:3-7-supply-side-policies:match:d1ecc951', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Corporation tax”?", "options": ["Public sector spending reducing the funds or opportunities available to the private sector", "Policy that restricts unions'' power to negotiate pay and conditions", "A tax on a firm''s profits", "The skills, knowledge and qualifications that make a worker productive"]}'::jsonb, '{"answer": 2, "explain": "“Corporation tax” means: A tax on a firm''s profits"}'::jsonb),
('economics:3-7-supply-side-policies:match:5ea6c64b', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Trade union reform”?", "options": ["Policy that restricts unions'' power to negotiate pay and conditions", "Public sector spending reducing the funds or opportunities available to the private sector", "A tax on a firm''s profits", "A benefit to a third party not involved in a transaction, e.g. from vaccination"]}'::jsonb, '{"answer": 0, "explain": "“Trade union reform” means: Policy that restricts unions'' power to negotiate pay and conditions"}'::jsonb),
('economics:3-7-supply-side-policies:match:889ce214', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Privatisation”?", "options": ["Policy that restricts unions'' power to negotiate pay and conditions", "The next best alternative given up when a choice is made", "The UK body that can block mergers that would reduce competition", "Selling a state-owned organisation into the private sector"]}'::jsonb, '{"answer": 3, "explain": "“Privatisation” means: Selling a state-owned organisation into the private sector"}'::jsonb),
('economics:3-7-supply-side-policies:match:9c028b3e', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Deregulation”?", "options": ["The skills, knowledge and qualifications that make a worker productive", "Removing rules and regulations that create barriers to entry in a market", "Public sector spending reducing the funds or opportunities available to the private sector", "Policy that restricts unions'' power to negotiate pay and conditions"]}'::jsonb, '{"answer": 1, "explain": "“Deregulation” means: Removing rules and regulations that create barriers to entry in a market"}'::jsonb),
('economics:3-7-supply-side-policies:match:cc72940a', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Competition and Markets Authority (CMA)”?", "options": ["The UK body that can block mergers that would reduce competition", "Removing rules and regulations that create barriers to entry in a market", "A tax on income or profit, such as income tax or corporation tax", "The next best alternative given up when a choice is made"]}'::jsonb, '{"answer": 0, "explain": "“Competition and Markets Authority (CMA)” means: The UK body that can block mergers that would reduce competition"}'::jsonb),
('economics:3-7-supply-side-policies:match:0e7af0bd', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Crowding out”?", "options": ["Selling a state-owned organisation into the private sector", "Public sector spending reducing the funds or opportunities available to the private sector", "Removing rules and regulations that create barriers to entry in a market", "A benefit to a third party not involved in a transaction, e.g. from vaccination"]}'::jsonb, '{"answer": 1, "explain": "“Crowding out” means: Public sector spending reducing the funds or opportunities available to the private sector"}'::jsonb),
('economics:3-7-supply-side-policies:match:1b9035ab', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Opportunity cost”?", "options": ["Unemployment caused by a mismatch between workers'' skills and available jobs", "The next best alternative given up when a choice is made", "Policy that restricts unions'' power to negotiate pay and conditions", "The UK body that can block mergers that would reduce competition"]}'::jsonb, '{"answer": 1, "explain": "“Opportunity cost” means: The next best alternative given up when a choice is made"}'::jsonb),
('economics:3-7-supply-side-policies:match:4ec04645', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Structural unemployment”?", "options": ["The UK body that can block mergers that would reduce competition", "A tax on a firm''s profits", "Government policy aimed at increasing the economy''s productive capacity, rather than managing demand", "Unemployment caused by a mismatch between workers'' skills and available jobs"]}'::jsonb, '{"answer": 3, "explain": "“Structural unemployment” means: Unemployment caused by a mismatch between workers'' skills and available jobs"}'::jsonb),
('economics:3-7-supply-side-policies:match:9235043f', 'economics', 'economics:3-7-supply-side-policies', '3.7 Supply-Side Policies', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Positive externality”?", "options": ["The UK body that can block mergers that would reduce competition", "Transport, energy and communication networks that support economic activity", "A benefit to a third party not involved in a transaction, e.g. from vaccination", "Government policy aimed at increasing the economy''s productive capacity, rather than managing demand"]}'::jsonb, '{"answer": 2, "explain": "“Positive externality” means: A benefit to a third party not involved in a transaction, e.g. from vaccination"}'::jsonb),
('economics:3-8-limitations-of-markets:exam:90a1b54d', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q2", "question": "Which one of the following produces an externality?", "options": ["A manufactured good", "A tent", "An imported good", "Education"], "hint": "An externality affects a THIRD PARTY outside the transaction. A manufactured/imported good or a tent are just normal private purchases — only education spills benefits onto people who never paid for it.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: D — Education</strong></p>\n<ul>\n<li>Education creates a positive externality: the wider community benefits from a more educated population, not just the person being educated. A manufactured, imported good, or a tent are ordinary private purchases with no third-party spillover.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:b7a02552', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q3", "question": "Why can pollution be seen as an example of an externality?", "options": ["Firms will disregard government controls", "Pollution causes inflation", "The firm''s costs differ from the costs to society", "The polluting firm''s price will be too high"], "hint": "The core definition of an externality is a gap between the PRIVATE cost the firm pays and the cost to SOCIETY, which includes people the firm never compensates.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1 1b)</h5>\n<p><strong>Answer: C — The firm''s costs differ from the costs to society</strong></p>\n<ul>\n<li>This is the definition of an externality: a gap between private cost (what the firm pays) and social cost (what society actually bears).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:f2996b51', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q4", "question": "A chemical firm is dumping toxic waste into a stream resulting in the death of fish at a fish farm. Which one of the following is the most appropriate government policy?", "options": ["Do nothing", "Subsidise the chemical firm", "Tax the chemical firm", "Tax the fish farm"], "hint": "The polluter-pays principle: tax the firm CAUSING the externality (the chemical firm), not the victim (the fish farm), and not with a subsidy, which would only encourage more pollution.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — Tax the chemical firm</strong></p>\n<ul>\n<li>Taxing the producer causing the negative externality forces it to internalise the external cost. Taxing the victim (the fish farm) or subsidising the polluter would make the problem worse, not better.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:698b62bf', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q6", "question": "Which statement shows a negative externality affecting a worker in the car industry?", "options": ["A worker is retrained so they can use new machinery as part of their job", "A worker is unable to get to work due to train drivers being on strike", "A worker loses their job due to increased use of automation", "A worker takes time off to have medical tests provided by their employer"], "hint": "An externality must hit someone OUTSIDE the transaction that caused it. The train strike is completely unrelated to the car worker''s own job, yet it stops them getting to work — that''s a spillover onto a third party. Losing a job to automation is a direct consequence of the employer''s own decision, not a third-party spillover.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — A worker is unable to get to work due to train drivers being on strike</strong></p>\n<ul>\n<li>The rail strike is an activity the car worker had no part in, yet it harms them — a genuine third-party spillover effect.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered B correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:c01c5045', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q7", "question": "Education results in positive externalities being generated. To ensure that these are internalised the UK government provides state education. What is an opportunity cost of this decision?", "options": ["The cost of paying teachers", "The excess demand for health services", "The money spent on producing examinations", "The need to ensure all children attend school"], "hint": "Opportunity cost is the next best alternative FOREGONE, not a cost that''s already part of running the policy itself. Paying teachers, producing exams and enforcing attendance are all COSTS of education; what''s genuinely given up is what those same government funds could have gone towards instead, such as health services.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — The excess demand for health services</strong></p>\n<ul>\n<li>The other three options are direct COSTS of running education itself, not an opportunity cost. The genuine opportunity cost is the alternative government spending (e.g. on health services) that is given up.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates answered B correctly, although a relatively common misconception was confusing opportunity cost with a private cost so incorrectly selecting A.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:460408e9', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q8", "question": "Indirect taxation is one policy a government can use to correct negative externalities. This policy works through the", "options": ["demand curve shifting to the right as prices increase", "quantity sold decreasing as the demand curve shifts to the left", "supply curve shifting to the left leading to higher prices", "supply curve shifting to the right as supply decreases"], "hint": "A tax raises firms'' production costs, which is a SUPPLY-side effect. Follow it through: supply shifts left, so price rises and quantity falls. Demand never shifts because of a tax on the seller.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — supply curve shifting to the left leading to higher prices</strong></p>\n<ul>\n<li>A tax raises the firm''s cost of production, shifting SUPPLY left. Demand is unaffected by a tax on the seller.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>This was a question that tested candidates'' knowledge of the market mechanism diagram and effectively rewarded candidates who could use it effectively.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:110067e5', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q9", "question": "A government intends to use information provision to encourage the consumption of a good which has a positive externality. Why would a policy of information provision be unsuccessful?", "options": ["Demand is highly price elastic", "Supply is perfectly price inelastic", "There is a high level of internet use in the country", "There is excess supply of the good"], "hint": "Information provision works by shifting DEMAND right. But if supply cannot respond at all (perfectly inelastic — fixed at one quantity), a rightward shift in demand just raises price; the quantity actually consumed barely changes.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Supply is perfectly price inelastic</strong></p>\n<ul>\n<li>If supply cannot expand at all, shifting demand right through information provision only raises price — the quantity consumed stays the same.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Many candidates answered B correctly.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:b3fadf2e', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q10", "question": "A positive externality is", "options": ["any external cost which occurs as supply increases", "any positive consequence of a firm employing more workers in the long run", "the beneficial effect of production on someone not consuming the product", "the benefit a person gains from consuming a newly invented product"], "hint": "A positive externality is a benefit that spills onto someone NOT involved in the transaction — ''a beneficial effect on someone not consuming the product'' captures the THIRD PARTY test exactly.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: C — the beneficial effect of production on someone not consuming the product</strong></p>\n<ul>\n<li>This is the third-party test for a positive externality. Options A, B and D describe private costs/benefits, not spillovers to outsiders.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered C.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:25cdb55b', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q11", "question": "Limits on who can buy tobacco and where people are allowed to smoke are examples of regulation to correct negative externalities. What is a benefit of regulation as a policy to correct negative externalities?", "options": ["Consumption of the product will fall to zero", "It can lead to a change in personal attitudes and behaviour", "It will always result in lower prices", "The government will have to spend money on policing the policy"], "hint": "Regulation isn''t just about the rule itself — over time it can shift how people actually think and behave, beyond the immediate ban. Watch the traps: ''fall to zero'' and ''always'' are absolute claims, and policing costs are a COST, not a benefit.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — It can lead to a change in personal attitudes and behaviour</strong></p>\n<ul>\n<li>Regulation can shift social norms over time, not just restrict the transaction itself. The other options are either an overstatement (\"fall to zero\", \"always\") or a cost, not a benefit.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A significant proportion of candidates correctly answered B.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:97b5415c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q12", "question": "The government wants to reduce the levels of pollution by encouraging more individuals to use public transport. In which of the following market diagrams for public transport will a subsidy have the greatest effect?", "options": ["Diagram A", "Diagram B", "Diagram C", "Diagram D"], "caseStudy": "<p><strong>Market diagrams for public transport</strong></p>\n<img src=\"/images/economics/3-8-public-transport-subsidy-diagrams-mcq-extracted.png\" alt=\"Four small supply-and-demand diagrams labelled A to D for the public transport market. A shows a normal downward-sloping demand curve and a normal upward-sloping supply curve crossing in the middle. B shows a normal downward-sloping demand curve D and a perfectly elastic (horizontal) supply curve S. C shows a perfectly inelastic (vertical) demand curve D crossing a normal upward-sloping supply curve S. D shows a perfectly elastic (horizontal) demand curve D and a normal upward-sloping supply curve S\" style=\"display:block;width:100%;max-width:620px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />", "hint": "A subsidy shifts supply. The diagram where a shift in supply moves quantity the MOST is the one with the flattest (most price ELASTIC) demand curve — check which option has a near-horizontal D.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: D</strong></p>\n<ul>\n<li>''D'' is correct because the price elasticity of demand is perfectly elastic, so quantity will respond the most to a change in supply.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Some candidates used the diagrams in the exam paper to draw new supply curves (post-subsidy) to aid their answering of the question, which usually helped.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:75d6a2dc', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q13", "question": "The government brings in new legislation to ban the use of sugar in sweets and soft drinks. What is the main opportunity cost to the government of enforcing this ban? The money spent on", "options": ["enforcement could have been spent on other activities", "government provision of sweets and soft drinks", "providing information about the danger of too much sugar", "regulating the imports of foreign-made products"], "hint": "''The main opportunity cost of enforcing this ban'' points to the enforcement BUDGET itself — what else that money could have funded — not one of the ban''s other side-effects.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: A — enforcement could have been spent on other activities</strong></p>\n<ul>\n<li>This directly completes the opportunity-cost idea in the stem: money spent enforcing the ban could have funded something else instead.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A majority of candidates gave Option A as the correct response to this question. This answer fully completes the sentence started in the stem with the idea of opportunity cost.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:0cc96e82', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q14", "question": "The government wishes to correct a problem of a negative externality. Its best policy is to", "options": ["lower income taxes on consumers", "raise income taxes on consumers", "subsidise the producer of the externality", "tax the producer of the externality"], "hint": "Correcting a negative externality means making the CAUSE (the producer) pay the full social cost of their output — that''s a tax on the producer, not an income tax change or a subsidy.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — tax the producer of the externality</strong></p>\n<ul>\n<li>Taxing the producer causing the externality directly raises their costs, correcting the private-versus-social cost gap.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option D as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:7f12568a', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q15", "question": "During production of a good, a firm releases a harmful gas into the atmosphere. This is best described as", "options": ["a lack of government regulation", "a negative externality", "an input of the primary sector", "an output of the secondary sector"], "hint": "This is the textbook scenario: a cost imposed on third parties (people breathing the gas) that isn''t reflected in the firm''s own costs of production.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — a negative externality</strong></p>\n<ul>\n<li>The harmful gas imposes a cost on third parties not reflected in the firm''s own costs — the definition of a negative externality.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>A high percentage of candidates gave Option B as the correct response to this question.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:f8e4d957', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q16", "question": "Which of the following leads to a positive externality?", "options": ["A subsidy", "A tax", "A vaccination", "An export"], "hint": "Of the four options, only vaccination creates a benefit for people OTHER than the person consuming it — herd immunity for people like Tom.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — A vaccination</strong></p>\n<ul>\n<li>A subsidy and a tax are POLICIES governments use to correct externalities, not externalities themselves; an export is simply a private sale abroad.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:c085d7f7', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q17", "question": "Which of the following is a possible cost if a government increases taxation to reduce a negative externality?", "options": ["A decrease in government revenue", "An increase in government revenue", "Growth in unofficial markets", "Less spending on healthcare"], "hint": "Higher taxes on a good people still want to buy can push trade underground into black/unofficial markets — a real cost, even though tax revenue itself would normally RISE, not fall.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — Growth in unofficial markets</strong></p>\n<ul>\n<li>Higher duties can push trade into black/counterfeit markets, losing the government tax revenue it was hoping to raise.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:73e3b819', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q18", "question": "Which of the following is not a policy to correct an externality?", "options": ["Free trade agreement", "Legislation", "Regulation", "State provision"], "hint": "The five government policies to correct externalities are taxation, subsidies, state provision, legislation/regulation, and information provision. A free trade agreement is a trade policy, not one of these five.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1a)</h5>\n<p><strong>Answer: A — Free trade agreement</strong></p>\n<ul>\n<li>Legislation, regulation and state provision are all standard policies to correct externalities. A free trade agreement is not.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:8da6bc2e', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q19", "question": "A firm releases a harmful gas into the air. Which of these statements is correct?", "options": ["Output of the good creates a negative externality", "Output of the good is less than the optimum for society", "The firm cannot be maximising profits", "The government should subsidise the firm''s production"], "hint": "Careful with the other options: output is actually MORE than the social optimum, not less, since the free market overproduces goods with negative externalities. A firm can still maximise its own profit while imposing costs on others, and subsidising a polluter would only make things worse.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: A — Output of the good creates a negative externality</strong></p>\n<ul>\n<li>The harmful gas is a direct negative externality of the firm''s output. Output is actually GREATER than the social optimum (not less), the firm can still be maximising profit, and a subsidy would only encourage more pollution.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:e1632060', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q20", "question": "A government decides to impose a tax on a product to reduce consumption. The effectiveness of this will be reduced if a characteristic of the product is", "options": ["elastic supply", "large opportunity costs", "low average costs", "price inelastic demand"], "hint": "A tax works by raising price to cut quantity demanded. If demand is price INELASTIC, quantity barely responds to the higher price, so the tax has little effect on consumption.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 3, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: D — price inelastic demand</strong></p>\n<ul>\n<li>When demand barely responds to price, a tax raises price without cutting quantity by much — the policy is less effective.</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>Examiner''s Comments</h5>\n<p>Several candidates responded ''B'' (large opportunity costs), which demonstrates a misconception of the term opportunity cost.</p>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:2a1afb43', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q22", "question": "When Mary gets a vaccination against a disease, Tom is also less likely to be infected by that disease. This is an example of:", "options": ["a government subsidy", "a negative externality", "a positive externality", "a social cost"], "hint": "Tom benefits from Mary''s vaccination without paying for it himself — a benefit to a third party outside the original transaction.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: C — a positive externality</strong></p>\n<ul>\n<li>Tom gains a benefit (lower infection risk) from Mary''s decision, without being part of that transaction himself.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:exam:e8b48b32', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'exam', 'mcq', 1, '{"num": "Q23", "question": "If a government wanted to reduce consumption of a good with a highly price inelastic demand which policy would have the most effect?", "options": ["Information provision", "Legislation", "State provision", "Taxation"], "hint": "Price-based tools like taxation barely work against inelastic demand, since quantity won''t respond much to a higher price. A ban (legislation) removes the good from the market directly, regardless of how strongly people want it.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO1b)</h5>\n<p><strong>Answer: B — Legislation</strong></p>\n<ul>\n<li>Because quantity demanded barely responds to price when demand is inelastic, taxation has limited effect. Legislation restricts or bans the good directly, which works regardless of elasticity — the mirror image of Q20.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:61dcb43a', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "An externality is best defined as a cost or benefit of an economic activity that falls on...", "options": ["A third party not involved in the transaction", "The firm producing the good", "The consumer who pays for the good", "The government"]}'::jsonb, '{"answer": 0, "explain": "An externality is a spillover effect on someone OUTSIDE the original transaction — not the buyer or seller themselves."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:b4835902', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "When the social cost of an activity is greater than its private cost, this is called a...", "options": ["Negative externality", "Public good", "Merit good", "Positive externality"]}'::jsonb, '{"answer": 0, "explain": "Social cost greater than private cost means a third party bears costs the producer or consumer never pays for — the definition of a negative externality."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:267bcd9d', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "Which of these is an example of a negative CONSUMPTION externality?", "options": ["A construction firm making noise on a building site", "A smoker polluting the air in a crowded room", "A factory dumping chemicals into a river", "A firm releasing toxic gas during production"]}'::jsonb, '{"answer": 1, "explain": "Consumption externalities come from CONSUMERS. The other three options are all caused by producers — negative production externalities."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:36f869f6', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "A subsidy is best described as...", "options": ["A government information campaign", "A law that bans a harmful activity", "Money paid to a producer to increase the supply of a good", "A tax charged on a good or service"]}'::jsonb, '{"answer": 2, "explain": "A subsidy lowers a firm''s costs so it can supply more at a lower price — used to correct the underprovision of goods with positive externalities."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:fdce618c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "Which policy directly ensures everyone has access to a good regardless of their ability to pay?", "options": ["State provision", "Taxation", "Information provision", "A subsidy"]}'::jsonb, '{"answer": 0, "explain": "State provision means the government supplies the good itself, e.g. the NHS or state education, guaranteeing access."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:afbe224d', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "The government wants to reduce cigarette consumption. Why is taxation alone often only partly effective?", "options": ["Cigarettes have no negative externality", "Demand for cigarettes is perfectly elastic", "Demand for cigarettes is price inelastic because they are addictive", "Cigarette supply is perfectly elastic"]}'::jsonb, '{"answer": 2, "explain": "Because smoking is addictive, demand barely responds to a higher price — quantity falls only a little even though the price rises."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:74a7556b', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "What is the free-rider problem?", "options": ["Firms avoiding tax by moving production abroad", "People benefiting from a good without paying for it", "The government running a budget deficit", "Consumers switching to a cheaper substitute good"]}'::jsonb, '{"answer": 1, "explain": "The free-rider problem is why firms won''t supply public goods and why positive-externality goods are underprovided — people can enjoy the benefit without paying."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:7cd50e55', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "A government spends £2 million enforcing a ban on a harmful product. What is the opportunity cost of this spending?", "options": ["The £2 million itself", "The next best alternative the £2 million could have been spent on", "The tax revenue lost from the ban", "The harm caused by the banned product"]}'::jsonb, '{"answer": 1, "explain": "Opportunity cost is always the NEXT BEST ALTERNATIVE forgone, not the spending itself or the problem the policy is trying to solve."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:e7f47b0c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "Vaccination is a real exam example of a...", "options": ["Negative externality", "Positive externality", "Demerit good", "Public good only"]}'::jsonb, '{"answer": 1, "explain": "If one person is vaccinated, others around them are also less likely to catch the disease — a benefit to third parties who never paid for it."}'::jsonb),
('economics:3-8-limitations-of-markets:mcq:0186eadf', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine limitation of using legislation to correct a negative externality?", "options": ["It never changes behaviour", "It can be costly and difficult to enforce", "It always creates a black market", "It has no opportunity cost"]}'::jsonb, '{"answer": 1, "explain": "Regulation is only as effective as the government''s ability to detect and prosecute breaches — enforcement itself has a real cost."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:97ea7b50', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "An externality can only ever affect the government."}'::jsonb, '{"answer": false, "explain": "An externality affects a THIRD PARTY generally — an individual, a firm, or society as a whole, not just the government."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:7ac65975', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "The free market tends to overproduce goods with negative externalities."}'::jsonb, '{"answer": true, "explain": "Producers and consumers ignore the external cost they impose on others, so more of the good is made and sold than is socially optimal."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:b3c1b255', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "The free market tends to overproduce goods with positive externalities."}'::jsonb, '{"answer": false, "explain": "It actually UNDERPRODUCES them — the free-rider problem means the external benefit isn''t paid for, so less is supplied than is socially optimal."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:47cb1e11', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "Taxing the producer of a negative externality is the government''s best policy to correct it."}'::jsonb, '{"answer": true, "explain": "This directly makes the producer face the social cost of their output, correcting the gap between private and social cost."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:2f881794', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "Subsidies are normally given to encourage the consumption of demerit goods."}'::jsonb, '{"answer": false, "explain": "Subsidies encourage MERIT goods and goods with positive externalities. Demerit goods (like tobacco) are usually taxed, not subsidised."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:535a2986', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "Legislation is always cheap and easy to enforce."}'::jsonb, '{"answer": false, "explain": "Enforcement can be costly, and some breaches (like fly-tipping) are hard to detect and prosecute — regulation is only as effective as its enforcement."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:7db5ab9c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "The opportunity cost of a policy is the money actually spent running it."}'::jsonb, '{"answer": false, "explain": "Opportunity cost is the NEXT BEST ALTERNATIVE forgone, not the policy''s own direct running cost."}'::jsonb),
('economics:3-8-limitations-of-markets:tf:7b374c9c', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tf', 'tf', 1, '{"question": "Vaccinating one person can also benefit other people who were not vaccinated."}'::jsonb, '{"answer": true, "explain": "This is the Mary-and-Tom example: Mary''s vaccination also makes Tom less likely to catch the disease — a positive externality."}'::jsonb),
('economics:3-8-limitations-of-markets:learn:6675e477', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'learn', 'mcq', 1, '{"readingTitle": "Positive and negative externalities", "reading": "<p><strong>An externality is a cost or benefit of an economic activity that falls on a third party</strong> — someone who was not part of the original decision to produce or consume the good.</p>\n<h4>Negative externalities — social cost greater than private cost</h4>\n<ul>\n<li><strong>Private cost</strong> is what the producer or consumer actually pays. <strong>Social cost</strong> = the private cost PLUS the external cost imposed on third parties.</li>\n<li>When social cost is greater than private cost, the activity creates a <strong>negative externality</strong> — e.g. a factory''s air pollution costs nearby residents in poor health, even though the firm never pays for that harm. Pollution is a negative externality because \"the firm''s costs differ from the costs to society.\"</li>\n<li><strong>Negative production externalities</strong> come from producers, e.g. noisy construction disturbing local residents who are never compensated. <strong>Negative consumption externalities</strong> come from consumers, e.g. a smoker polluting the air in a confined space, or car journeys causing congestion.</li>\n<li>Because the producer or consumer ignores the external cost, the free market <strong>overproduces</strong> goods with negative externalities compared with the socially optimal amount.</li>\n</ul>\n<h4>Positive externalities — social benefit greater than private benefit</h4>\n<ul>\n<li><strong>Private benefit</strong> is what the individual or firm receives directly. <strong>Social benefit</strong> = the private benefit PLUS the external benefit enjoyed by others, unpaid for — creating the <strong>free-rider problem</strong>.</li>\n<li>Classic exam example: if Mary gets vaccinated, Tom is also less likely to catch the disease from her — a benefit to Tom that he never paid for.</li>\n<li>Education is another example: a better-educated workforce benefits the whole economy, not just the person who was trained — this is why \"education\" (not a manufactured, imported good, or a tent) is the option that actually produces an externality.</li>\n<li>Because the free-rider effect isn''t paid for, the free market <strong>underproduces</strong> goods with positive externalities compared with the socially optimal amount.</li>\n</ul>", "question": "A chemical firm dumps toxic waste into a river, killing fish at a nearby fish farm. This is best explained by...", "options": ["Government regulation is too strict", "The firm''s private cost of production is lower than the social cost it creates", "The fish farm''s private cost is too high", "The firm is not maximising profit"]}'::jsonb, '{"answer": 1, "explain": "The firm only pays its own PRIVATE cost of production. It doesn''t pay for the damage to the fish farm, so the SOCIAL cost (private cost plus the cost to the fish farm) is higher than what the firm actually pays — the classic negative externality gap."}'::jsonb),
('economics:3-8-limitations-of-markets:learn:a488c6f9', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'learn', 'mcq', 1, '{"readingTitle": "Five government policies to correct externalities", "reading": "<p>The government has <strong>five main policies</strong> to correct the gap between private and social cost or benefit — the exam expects you to know how each one actually WORKS, not just its name.</p>\n<h4>1. Taxation — for negative externalities</h4>\n<ul>\n<li>An <strong>indirect tax</strong> (e.g. excise duty on tobacco or fuel) raises a firm''s cost of production, so <strong>supply shifts LEFT</strong>. This raises the market price and reduces the equilibrium quantity.</li>\n<li>The best policy for a negative externality is always to <strong>tax the producer causing it</strong> — not the victim, and not a subsidy.</li>\n</ul>\n<img src=\"/images/economics/3-8-petrol-tax-co2-supply-shift-ms-extracted.png\" alt=\"Supply and demand diagram: an indirect tax shifts supply from S to S+tax, raising the equilibrium price from P1 to P2 and lowering the equilibrium quantity from Q1 to Q2\" style=\"display:block;width:100%;max-width:420px;margin:14px auto;border:1px solid var(--border);border-radius:8px;background:#fff;padding:6px;\" />\n<p style=\"text-align:center;font-size:13px;color:var(--mid);\">A UK petrol tax of 52.95p per litre: supply shifts left, price rises P1→P2, quantity falls Q1→Q2 — and since petrol use causes CO2 emissions, the fall in quantity should cut emissions (by an amount that depends on how price inelastic demand for petrol is).</p>\n<h4>2. Subsidies — for positive externalities</h4>\n<ul>\n<li>A <strong>subsidy</strong> is money paid to a producer to lower their costs, increasing supply and lowering the price to consumers — used to encourage consumption of merit goods and goods with positive externalities, e.g. vaccinations.</li>\n</ul>\n<h4>3. State provision</h4>\n<ul>\n<li>The government directly supplies goods it believes are under-provided by the market: merit goods like state education and the NHS, and public goods like defence and street lighting, which the private sector won''t supply because of the free-rider problem.</li>\n</ul>\n<h4>4. Legislation and regulation</h4>\n<ul>\n<li>Laws that ban or restrict harmful activities directly, e.g. age limits on buying tobacco, or restrictions on where people are allowed to smoke.</li>\n</ul>\n<h4>5. Information provision</h4>\n<ul>\n<li>Government campaigns that encourage consumption of goods with positive externalities, or discourage consumption of goods with negative externalities, e.g. anti-smoking health warnings.</li>\n</ul>", "question": "Indirect taxation corrects a negative externality by working through the...", "options": ["demand curve shifting right as prices increase", "supply curve shifting right as supply decreases", "quantity sold decreasing as the demand curve shifts left", "supply curve shifting left, leading to higher prices"]}'::jsonb, '{"answer": 3, "explain": "A tax raises a firm''s costs of production, so the SUPPLY curve shifts left — this raises price and cuts the equilibrium quantity. Demand does not shift at all; that is the most common exam misconception on this topic."}'::jsonb),
('economics:3-8-limitations-of-markets:learn:40325d74', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating the use and impact of policies", "reading": "<p>Every one of the five policies has a genuine weakness — the exam rewards you for weighing these up, not just listing benefits.</p>\n<h4>Taxation</h4>\n<ul>\n<li><strong>Limited by inelastic demand</strong>: addictive goods like tobacco and alcohol have price INELASTIC demand, so a tax barely reduces the quantity consumed — this is why legislation (an outright ban) has more effect than taxation on a highly price-inelastic good.</li>\n<li><strong>Can create black markets</strong>: high excise duties can push trade into unofficial or counterfeit markets, which loses the government tax revenue and can be more dangerous, since counterfeit products can contain harmful ingredients.</li>\n</ul>\n<h4>Subsidies</h4>\n<ul>\n<li>Effectiveness depends on <strong>elasticity</strong> — subsidising a good with elastic demand causes a much bigger rise in quantity consumed than subsidising a good with inelastic demand.</li>\n<li>Only works if <strong>supply can actually respond</strong> — if supply is perfectly inelastic (fixed), a policy that raises demand (like information provision) doesn''t raise the quantity actually consumed at all.</li>\n</ul>\n<h4>State provision</h4>\n<ul>\n<li>Guarantees access regardless of income, but quality can vary sharply by area, and services like the NHS can face long waiting lists — those who can afford private alternatives get faster treatment, which can widen inequality rather than close it.</li>\n</ul>\n<h4>Legislation and regulation</h4>\n<ul>\n<li>Only as effective as its <strong>enforcement</strong>: breaches can be hard to detect and costly to prosecute (e.g. fly-tipping). Banning a good outright can also create a black market rather than eliminating the activity.</li>\n</ul>\n<h4>Information provision</h4>\n<ul>\n<li>Effectiveness depends entirely on how well it''s received — campaigns against addictive products have limited success precisely because addiction makes people hard to persuade.</li>\n</ul>", "question": "A government wants to reduce consumption of a good with highly price-inelastic demand. Which policy has the most effect?", "options": ["Information provision", "A subsidy", "Legislation", "Taxation"]}'::jsonb, '{"answer": 2, "explain": "Price-based tools like taxation barely work when quantity demanded won''t respond much to price. Legislation removes or restricts the good directly, regardless of how strongly people still want it."}'::jsonb),
('economics:3-8-limitations-of-markets:learn:f0bcdcbd', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'learn', 'mcq', 1, '{"readingTitle": "Evaluating costs and benefits, including opportunity cost", "reading": "<p>Government intervention isn''t free. Whichever policy you''re evaluating, the exam wants you to weigh the <strong>benefit against a genuine cost</strong> — and crucially, to PAIR them together, not just list two separate, unlinked points.</p>\n<h4>Opportunity cost — the government''s money has to come from somewhere</h4>\n<ul>\n<li><strong>Opportunity cost</strong> = the next best alternative given up when a choice is made. Money spent enforcing a ban could have been spent on other government activities. Money spent subsidising renewable energy could instead have funded health or education.</li>\n<li>Careful: the opportunity cost of a policy is NOT one of its own direct running costs — e.g. paying teachers is a cost of running education, not education''s opportunity cost. The opportunity cost is what else that same money could have achieved.</li>\n</ul>\n<h4>Costs to households</h4>\n<ul>\n<li>Policies to reduce negative externalities often raise costs for consumers too: higher electricity bills, more expensive petrol, and the higher cost of energy-efficient appliances or electric/hybrid cars.</li>\n</ul>\n<h4>Benefits — and how to PAIR them properly</h4>\n<ul>\n<li>Benefits include: lower healthcare costs from fewer illnesses, a healthier and more productive workforce, tax revenue that can fund other services, and — in the long run — a reduction in the scale of a problem like climate change.</li>\n<li><strong>The examiners'' number-one evaluation rule</strong>: an evaluative point must be MATCHED to the analytical point just made. Writing \"vaccination improves productivity\" (a benefit) and then separately writing \"there''s an opportunity cost of government spending\" (unlinked) earns no evaluation credit — you must connect the two, e.g. \"...however, this productivity gain must be weighed against the schools and hospitals that opportunity cost could otherwise have funded.\"</li>\n</ul>", "question": "Why does the government spending more on renewable energy have an opportunity cost?", "options": ["Because firms will not invest in renewable energy", "Because renewable energy is always more expensive than fossil fuels", "Because the same money could have been spent on other services such as health or education", "Because it will definitely increase the budget deficit"]}'::jsonb, '{"answer": 2, "explain": "Opportunity cost is about the NEXT BEST ALTERNATIVE use of the same resources — government funds spent on renewables cannot also be spent on health, education or other valued services."}'::jsonb),
('economics:3-8-limitations-of-markets:misc:5ef9d066', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The opportunity cost of state education is the cost of paying teachers.\"</p><p><strong>✅ The correct idea:</strong> Paying teachers, producing exams and making sure children attend school are all COSTS of running education — they are not its opportunity cost. The mark scheme''s own answer to this exact question is ''the excess demand for health services'': the real opportunity cost is what the same government money could have been spent on instead. The examiners explicitly flagged that a common wrong answer was confusing opportunity cost with a private/direct cost of the policy itself.</p>", "question": "The government spends money on state education. Which of these is genuinely the OPPORTUNITY COST of this decision?", "options": ["The cost of producing examinations", "The cost of paying teachers'' salaries", "The requirement that all children attend school", "The alternative government spending, e.g. on health services, that is given up"]}'::jsonb, '{"answer": 3, "explain": "Paying teachers, producing exams and enforcing attendance are all direct COSTS of running education. The opportunity cost is the alternative use of that same money — such as health services — that had to be given up."}'::jsonb),
('economics:3-8-limitations-of-markets:misc:b83fedf4', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"For a ''using a diagram, analyse...'' question, a written description is enough — the diagram itself doesn''t really matter.\"</p><p><strong>✅ The correct idea:</strong> The real mark scheme is blunt: ''A maximum of 4 marks if no correct diagram'' out of 6 — and application marks can ONLY be rewarded once there is also analysis, i.e. simply labelling a diagram earns nothing on its own. The Examiner''s Comments for this exact question were positive: ''Many candidates were able to draw an accurate diagram and write an analysis that drew on the context and impact of taxation... candidates generally had a very good understanding of the implications of inelastic price elasticity of demand.''</p>", "question": "On a ''using a diagram, analyse the impact of an indirect tax'' 6-mark question, what is the maximum mark available with NO correct diagram?", "options": ["2 out of 6", "6 out of 6", "0 out of 6", "4 out of 6"]}'::jsonb, '{"answer": 3, "explain": "The mark scheme states clearly: ''a maximum of 4 marks if no correct diagram.'' The diagram carries real marks, not just presentation credit."}'::jsonb),
('economics:3-8-limitations-of-markets:misc:b50bfcc5', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"An indirect tax on petrol shifts the DEMAND curve left, which is why price rises.\"</p><p><strong>✅ The correct idea:</strong> This is the exact misconception the examiners flagged in the mark scheme guidance: ''The most common misconceptions were that indirect taxes would cause demand to shift. Also, several candidates were using a macroeconomic diagram with AD, AS, price level and output which is incorrect.'' A tax raises the firm''s COST OF PRODUCTION, so it is the SUPPLY curve that shifts left (labelled ''S + tax''); demand is completely unaffected by a tax on the seller.</p>", "question": "An indirect tax is placed on petrol. What actually shifts on the correct market diagram?", "options": ["Both supply and demand shift left", "Supply shifts left", "Demand shifts left", "Neither curve shifts, only the price label changes"]}'::jsonb, '{"answer": 1, "explain": "A tax raises the firm''s cost of production, so SUPPLY shifts left to ''S + tax''. Demand is not affected by a tax charged to the seller."}'::jsonb),
('economics:3-8-limitations-of-markets:misc:b051509e', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"To evaluate, just write one point in favour of the policy and a separate point against it.\"</p><p><strong>✅ The correct idea:</strong> The real OCR misconception box for the vaccination-subsidy question is explicit: ''Evaluation is awarded for making a judgement or writing an evaluative point that matches with the preceding point... A common error was that candidates would analyse a benefit such as improved living standards/output in the economy and then attempt evaluation by writing that there is an opportunity cost of government spending WITHOUT LINKING this argument to how it would lower the potential gains.'' An unlinked ''however'' sentence earns nothing — it must connect directly back to the specific benefit just analysed.</p>", "question": "According to the OCR mark scheme, when does a ''however'' sentence actually earn evaluation marks?", "options": ["When it directly links back to and weighs up the specific point made just before it", "Whenever the answer includes the word ''however''", "Whenever it mentions an opportunity cost", "Only in the final sentence of the answer"]}'::jsonb, '{"answer": 0, "explain": "The mark scheme''s own misconception note says evaluation must MATCH the preceding analytical point. An unlinked opportunity-cost point that doesn''t weigh against the specific benefit just described earns no evaluation credit."}'::jsonb),
('economics:3-8-limitations-of-markets:misc:50f272a0', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"A calculation answer is worth full marks if the number is correct, even with no units.\"</p><p><strong>✅ The correct idea:</strong> The real Assessment for Learning note on this exact question says: ''When teaching quantitative skills, make sure students regularly include the full units of measurement.'' The mark scheme backs this up: ''1 mark only if million metric tons is omitted'' — a numerically correct but unit-less answer loses a mark. The flip side is generous, though: ''1 mark for OFR (own figure rule) if graph is misread'' — showing your working still protects you even if you read the chart wrong.</p>", "question": "You calculate 58.89 × 9 = 530.01 correctly but write just \"530.01\" with no units. How many of the 2 marks do you get?", "options": ["2 marks, but only if it is rounded to 530", "1 mark — the units (million metric tons) are required for the second mark", "2 marks — the number is correct", "0 marks — units are always required for any mark at all"]}'::jsonb, '{"answer": 1, "explain": "The mark scheme is explicit: ''1 mark only if million metric tons is omitted.'' The correct number alone is not enough for full marks."}'::jsonb),
('economics:3-8-limitations-of-markets:tips:508d04b6', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tips', 'mcq', 1, '{"readingTitle": "definition — Define the externality gap precisely", "reading": "<p>Every definition question on this topic is really testing the same idea: a gap between what''s PRIVATE and what''s SOCIAL.</p>\n<ul>\n<li><strong>Externality</strong> = a cost or benefit of an economic activity that falls on a <strong>third party</strong> outside the original transaction.</li>\n<li><strong>Negative externality</strong>: social cost is GREATER than private cost. <strong>Positive externality</strong>: social benefit is GREATER than private benefit.</li>\n<li>The examiners repeatedly reward answers that name the THIRD PARTY test directly — vague answers like \"it''s bad for the environment\" without identifying who bears the cost score less well.</li>\n</ul>", "question": "Which phrase MUST appear in a strong definition of ''externality''?", "options": ["A cost paid by the producer", "A benefit received by the government", "A tax on a good or service", "A cost or benefit affecting a third party outside the transaction"]}'::jsonb, '{"answer": 3, "explain": "The third-party test is the core of the definition — without it, you''re just describing a normal private cost or benefit."}'::jsonb),
('economics:3-8-limitations-of-markets:tips:5e18cd86', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tips', 'mcq', 1, '{"readingTitle": "diagram — The signature 6-marker: ''Using a diagram, analyse a tax...''", "reading": "<p>This exact question type appeared as a 6-marker on the real paper — learn the routine cold.</p>\n<ul>\n<li><strong>Draw and label it</strong>: original S and D, then shift S left to \"S + tax\" (or S1). Label the new equilibrium P2 and Q2, and the original P1 and Q1. <strong>No correct diagram caps you at 4/6.</strong></li>\n<li><strong>Reference the extract''s numbers</strong>: e.g. \"the tax is 52.95p per litre.\"</li>\n<li><strong>Explain the mechanism</strong>: tax increases cost of production → decreases supply → increases equilibrium price → equilibrium quantity falls.</li>\n<li><strong>Scale it with elasticity</strong>: if demand is price INELASTIC (like petrol), the fall in quantity — and therefore the fall in whatever externality you''re correcting — is smaller than it would be with elastic demand.</li>\n<li><strong>Avoid the trap</strong>: it is SUPPLY that shifts, never demand, and never use a macroeconomic AD/AS diagram for a single market question.</li>\n</ul>", "question": "On a ''using a diagram, analyse a tax'' 6-marker, which curve should you shift?", "options": ["Supply, to the left", "Demand, to the left", "Demand, to the right", "Supply, to the right"]}'::jsonb, '{"answer": 0, "explain": "A tax raises the firm''s cost of production, so supply shifts LEFT. This is the single most commonly confused point on this question type."}'::jsonb),
('economics:3-8-limitations-of-markets:tips:4714f99f', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: pair every point, then judge on what it DEPENDS on", "reading": "<p>Evaluate questions on this topic ask you to weigh up whether a policy is worthwhile — the mark scheme rewards a very specific structure.</p>\n<ul>\n<li><strong>Pair every \"however\" with the point before it.</strong> An unlinked negative point (e.g. a generic mention of opportunity cost) earns no evaluation credit unless it directly weighs against the specific benefit you just analysed.</li>\n<li><strong>Use the extract''s own numbers</strong> as evidence for both sides, e.g. the UK''s rising measles vaccination coverage (81% in 2004 to over 91% in 2023) as evidence a subsidy is working.</li>\n<li><strong>Finish with a supported judgement that names what it DEPENDS ON</strong> — e.g. \"Overall, the policy is likely to benefit society, but the extent depends on how high take-up is and whether the healthcare savings are large enough to justify the opportunity cost.\" A judgement with nothing specific behind it just repeats the analysis.</li>\n</ul>", "question": "What is the strongest way to end a 6-mark Evaluate answer?", "options": ["A list of every point made, restated in order", "A definition of the key term used in the question", "A summary that repeats the analysis points already made", "A judgement that names the specific factor the outcome depends on"]}'::jsonb, '{"answer": 3, "explain": "A supported judgement names WHAT the outcome depends on (e.g. take-up rate, how the sizes of the costs and benefits compare) — that''s what separates Level 3 from Level 2."}'::jsonb),
('economics:3-8-limitations-of-markets:tips:7f21a046', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'tips', 'mcq', 1, '{"readingTitle": "opportunity cost — Opportunity cost is NOT a policy''s own running cost", "reading": "<p>This trips up more candidates than almost anything else on this paper.</p>\n<ul>\n<li><strong>Opportunity cost</strong> = the next best ALTERNATIVE given up, not a cost the policy directly creates. Enforcing a sugar ban has a cost (the money spent on enforcement) — but the OPPORTUNITY cost is what that money could have been spent on instead.</li>\n<li><strong>2 marks needs specifics</strong>: the mark scheme gives 2 marks for \"a correct explanation of opportunity cost that includes a reference to actual alternative uses of government spending,\" but only 1 mark for generic understanding with no specific alternative named.</li>\n<li><strong>Two worked examples</strong>: government spending on renewable energy could otherwise fund education or health (specific); or it could increase the budget deficit, meaning more has to be repaid later at the expense of other future spending.</li>\n</ul>", "question": "For 2 marks on ''explain an opportunity cost of the government''s renewable energy investment'', what does the mark scheme require?", "options": ["A calculation showing the exact amount spent", "Just the definition of opportunity cost", "A correct explanation that names a specific alternative use of the government spending given up", "A list of three different opportunity costs"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme awards 2 marks only when the answer names an actual alternative (e.g. health or education spending) — generic understanding without specifics is capped at 1 mark."}'::jsonb),
('economics:3-8-limitations-of-markets:fib:81fc79b1', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "An externality is a cost or benefit that falls on a ___B1___ party, and is not reflected in the market ___B2___.", "blankOptions": {"B1": ["supply", "another", "third", "tax"], "B2": ["paying", "left", "price", "alternative"]}}'::jsonb, '{"blanks": {"B1": "third", "B2": "price"}}'::jsonb),
('economics:3-8-limitations-of-markets:fib:d43001ac', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "When ___B1___ cost is greater than ___B2___ cost, an economic activity creates a negative externality.", "blankOptions": {"B1": ["another", "demand", "social", "free-rider"], "B2": ["private", "subsidy", "left", "right"]}}'::jsonb, '{"blanks": {"B1": "social", "B2": "private"}}'::jsonb),
('economics:3-8-limitations-of-markets:fib:ed701179', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "An indirect tax raises a firm''s costs, so the ___B1___ curve shifts ___B2___, raising price and cutting quantity.", "blankOptions": {"B1": ["demand", "supply", "private", "free-rider"], "B2": ["subsidy", "free-rider", "private", "left"]}}'::jsonb, '{"blanks": {"B1": "supply", "B2": "left"}}'::jsonb),
('economics:3-8-limitations-of-markets:fib:35558ace', 'economics', 'economics:3-8-limitations-of-markets', '3.8 Limitations of Markets', 'fib', 'fib', 2, '{"question": "A ___B1___ is money paid to a producer to lower costs and increase ___B2___.", "blankOptions": {"B1": ["subsidy", "private", "right", "price"], "B2": ["right", "alternative", "supply", "private"]}}'::jsonb, '{"blanks": {"B1": "subsidy", "B2": "supply"}}'::jsonb)
